const leadResult = $(''Busca Lead no CRM1'').first().json;
const dados = $(''Dados do Agendamento'').first().json;

const leadRecord = leadResult?.record || null;

const inputItems = $input.all().map(i => i.json);
let slots = [];

const first = $input.first().json;
if (Array.isArray(first)) {
  slots = first;
} else if (Array.isArray(first?.slots)) {
  slots = first.slots;
} else {
  slots = inputItems.filter(s => s && (s.startAt || s.endAt));
}

const slotsFormatados = slots.slice(0, 5).map((slot, i) => {
  const startIso = slot.startAt || slot;
  const d = new Date(startIso);
  const dias = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sab'];
  const meses = ['jan', 'fev', 'mar', 'abr', 'mai', 'jun', 'jul', 'ago', 'set', 'out', 'nov', 'dez'];
  return {
    numero: i + 1,
    iso: startIso,
    texto: `${i + 1}. ${dias[d.getDay()]}, ${d.getDate()} de ${meses[d.getMonth()]} às ${String(d.getHours()).padStart(2,'0')}h${String(d.getMinutes()).padStart(2,'0')}`
  };
});

return [{
  json: {
    ...dados,
    lead_encontrado: !!leadRecord,
    lead_nome: leadRecord?.name || dados.nome_pessoa,
    lead_protocolo: leadRecord?.code || '',
    lead_area: leadRecord?.classification || '',
    lead_atendimento_id: leadRecord?.id || '',
    slots_disponiveis: slotsFormatados,
    slots_texto: slotsFormatados.map(s => s.texto).join('\n'),
    tem_slots: slotsFormatados.length > 0
  }
}];

